using Microsoft.Extensions.Options;using Portal.Notification.Application;
namespace Portal.Notification.Worker;
public sealed class NotificationWorkerOptions{public bool Enabled{get;init;}=true;public int PollIntervalSeconds{get;init;}=5;public int BatchSize{get;init;}=25;public int MaxAttempts{get;init;}=5;public int BaseRetrySeconds{get;init;}=5;}
public sealed class NotificationBackgroundWorker(IServiceProvider services,IOptions<NotificationWorkerOptions> options,ILogger<NotificationBackgroundWorker> logger):BackgroundService
{protected override async Task ExecuteAsync(CancellationToken ct){if(!options.Value.Enabled){logger.LogInformation("Notification worker is disabled.");return;}while(!ct.IsCancellationRequested){try{await using var scope=services.CreateAsyncScope();var count=await scope.ServiceProvider.GetRequiredService<NotificationProcessor>().ProcessBatchAsync(options.Value.BatchSize,options.Value.MaxAttempts,TimeSpan.FromSeconds(options.Value.BaseRetrySeconds),ct);if(count>0)logger.LogInformation("Processed {MessageCount} notification messages",count);}catch(Exception e)when(!ct.IsCancellationRequested){logger.LogError(e,"Notification processing cycle failed");}await Task.Delay(TimeSpan.FromSeconds(Math.Max(1,options.Value.PollIntervalSeconds)),ct);}}}
